/* data+ :: content/quiz5.js — DA0-002 Domain 5 question bank (100 items). */
window.DATAPLUS = window.DATAPLUS || {}; DATAPLUS.questions = DATAPLUS.questions || [];
DATAPLUS.questions.push(
{ id:"D5-001", domain:5, obj:"5.1", diff:"easy", q:"A new analyst joins a team and cannot tell what the column 'cust_seg_cd' means or what valid values it accepts. Which documentation artifact would MOST directly answer this?", options:["Data flow diagram","Incident report","Data dictionary","Retention schedule"], answer:2, explain:"<strong>Data dictionary</strong> catalogs each field's name, data type, allowed values, and business meaning, so it directly explains what 'cust_seg_cd' represents and its valid values.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data flow diagram</b>: a flow diagram shows how data moves between systems, not the meaning or valid values of an individual column.</span><span class='qd'><b>Incident report</b>: an incident report documents a breach or operational event, not field definitions.</span><span class='qd'><b>Retention schedule</b>: a retention schedule specifies how long data is kept, not what a column means.</span>" },
{ id:"D5-002", domain:5, obj:"5.1", diff:"medium", q:"An auditor asks the analytics team to show exactly where a revenue figure in a dashboard originated, every transformation it passed through, and which source system produced it. Which artifact BEST satisfies this request?", options:["Data dictionary","Data classification policy","Service-level agreement","Data lineage"], answer:3, explain:"<strong>Data lineage</strong> traces data end to end, from source system through each transformation to the final report, which is precisely what the auditor needs to verify the revenue figure's origin.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data dictionary</b>: a data dictionary defines fields but does not trace the movement and transformation of a value across systems.</span><span class='qd'><b>Data classification policy</b>: classification labels sensitivity levels, not the path data took.</span><span class='qd'><b>Service-level agreement</b>: an SLA sets performance or availability commitments, not data provenance.</span>" },
{ id:"D5-003", domain:5, obj:"5.1", diff:"medium", q:"A company has customer records in the CRM, the billing system, and a marketing platform, and the values disagree. Leadership wants one authoritative version each system should defer to. Which concept addresses this?", options:["Data versioning","Source of truth","Data masking","Stress testing"], answer:1, explain:"<strong>Source of truth</strong> designates the single authoritative system or dataset that all others defer to, resolving the conflicting customer values across the three systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data versioning</b>: versioning tracks changes over time within a dataset, not which system is authoritative.</span><span class='qd'><b>Data masking</b>: masking obscures sensitive values and has nothing to do with reconciling authoritative records.</span><span class='qd'><b>Stress testing</b>: stress testing measures performance under load, unrelated to authoritative data.</span>" },
{ id:"D5-004", domain:5, obj:"5.1", diff:"hard", q:"An enterprise wants a governed program that consolidates and maintains consistent, accurate core entities such as customer, product, and vendor across all applications. Which discipline is this?", options:["Master data management","Extract, transform, load","Role-based access control","Data profiling"], answer:0, explain:"<strong>Master data management</strong> (MDM) is the governed discipline that creates and maintains a consistent, authoritative set of core entities like customer, product, and vendor across the enterprise.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Extract, transform, load</b>: ETL moves and reshapes data but does not by itself govern authoritative master entities.</span><span class='qd'><b>Role-based access control</b>: RBAC manages permissions, not the consolidation of core business entities.</span><span class='qd'><b>Data profiling</b>: profiling examines data characteristics for quality, not entity mastering.</span>" },
{ id:"D5-005", domain:5, obj:"5.1", diff:"easy", q:"Which term describes 'data about data,' such as the creation date, owner, and format of a file?", options:["Master data","Raw data","Metadata","Test data"], answer:2, explain:"<strong>Metadata</strong> is data about data, describing attributes like creation date, owner, schema, and format that help users find and understand a dataset.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Master data</b>: master data is the core business entities themselves, not descriptive attributes about other data.</span><span class='qd'><b>Raw data</b>: raw data is unprocessed source data, not the descriptive layer about it.</span><span class='qd'><b>Test data</b>: test data is sample data used for validation, not descriptive information about a file.</span>" },
{ id:"D5-006", domain:5, obj:"5.1", diff:"medium", q:"A data scientist must explain to regulators why a credit model rejected an applicant, describing which inputs drove the decision. Which governance concept supports this requirement?", options:["Data hierarchy","Data replication","Data silo","Explainability"], answer:3, explain:"<strong>Explainability</strong> is the ability to describe, in human terms, how a model or process arrived at its output, which is exactly what regulators demand for the credit decision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data hierarchy</b>: a hierarchy organizes data into parent-child levels and does not explain model decisions.</span><span class='qd'><b>Data replication</b>: replication copies data across locations and is unrelated to interpreting decisions.</span><span class='qd'><b>Data silo</b>: a silo is isolated, inaccessible data, the opposite of what aids explanation.</span>" },
{ id:"D5-007", domain:5, obj:"5.1", diff:"medium", q:"A diagram shows data entering from web forms, passing through an ETL job into a warehouse, then feeding a dashboard, using arrows to depict each movement. This artifact is BEST described as a:", options:["Data dictionary","Entity-relationship diagram","Data flow diagram","Retention matrix"], answer:2, explain:"<strong>Data flow diagram</strong> uses arrows and processes to depict how data moves through systems from intake to consumption, matching the described diagram.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data dictionary</b>: a dictionary lists field definitions, not the movement of data between processes.</span><span class='qd'><b>Entity-relationship diagram</b>: an ERD models table relationships and keys, not the runtime flow of data through ETL and dashboards.</span><span class='qd'><b>Retention matrix</b>: a retention matrix lists how long data types are kept, not data movement.</span>" },
{ id:"D5-008", domain:5, obj:"5.1", diff:"hard", q:"Two departments independently built customer datasets that never sync, so analytics produce contradictory totals. Which condition does this describe, and what governance practice MOST directly remedies it?", options:["A data breach remedied by incident reporting","Data drift remedied by retraining","A data silo remedied by integration into a single source of truth","Excessive load time remedied by indexing"], answer:2, explain:"<strong>A data silo remedied by integration into a single source of truth</strong> is correct: isolated departmental datasets are silos, and integrating them under an authoritative source resolves the contradictory totals.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A data breach remedied by incident reporting</b>: no unauthorized disclosure occurred; this is a consistency problem, not a security incident.</span><span class='qd'><b>Data drift remedied by retraining</b>: drift describes statistical change over time in a model's inputs, not duplicate disconnected datasets.</span><span class='qd'><b>Excessive load time remedied by indexing</b>: indexing addresses performance, not contradictory data sources.</span>" },
{ id:"D5-009", domain:5, obj:"5.1", diff:"easy", q:"Organizing data into levels such as country, then region, then city, then store reflects which concept?", options:["Data hierarchy","Data masking","Data retention","Data replication"], answer:0, explain:"<strong>Data hierarchy</strong> arranges data into nested parent-child levels such as country to region to city to store, enabling drill-down analysis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data masking</b>: masking obscures sensitive values, unrelated to organizing levels.</span><span class='qd'><b>Data retention</b>: retention concerns how long data is stored, not its structural levels.</span><span class='qd'><b>Data replication</b>: replication copies data across systems, not arranging it into levels.</span>" },
{ id:"D5-010", domain:5, obj:"5.1", diff:"medium", q:"A team needs to combine product data from an ERP, an e-commerce site, and a supplier feed into one warehouse table. This consolidation activity is BEST described as:", options:["Data integration","Data classification","Data anonymization","Data profiling"], answer:0, explain:"<strong>Data integration</strong> combines data from multiple disparate sources into a unified, consistent view, which is exactly the ERP, e-commerce, and supplier consolidation described.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data classification</b>: classification labels sensitivity, not the merging of sources.</span><span class='qd'><b>Data anonymization</b>: anonymization removes identifying details, not the act of combining sources.</span><span class='qd'><b>Data profiling</b>: profiling assesses data characteristics, not integration.</span>" },
{ id:"D5-011", domain:5, obj:"5.1", diff:"medium", q:"An analyst wants to keep periodic copies of a reporting table so they can reproduce last quarter's numbers exactly. Which technique enables reproducing prior states of the data?", options:["Data masking","Least privilege","Data versioning","Pseudonymization"], answer:2, explain:"<strong>Data versioning</strong> stores successive states or snapshots of a dataset so an analyst can reproduce the exact data as it existed at a prior point, such as last quarter.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data masking</b>: masking hides sensitive values and does not preserve historical states.</span><span class='qd'><b>Least privilege</b>: least privilege limits access rights, unrelated to reproducing prior data.</span><span class='qd'><b>Pseudonymization</b>: pseudonymization replaces identifiers with tokens, not preserving point-in-time copies.</span>" },
{ id:"D5-012", domain:5, obj:"5.1", diff:"hard", q:"A governance lead wants every dataset to carry searchable tags for owner, sensitivity, refresh cadence, and quality score so users can discover and trust data in a catalog. Investing in which asset BEST achieves this?", options:["Rich metadata management","Encryption at rest","Stress testing","Backout planning"], answer:0, explain:"<strong>Rich metadata management</strong> captures owner, sensitivity, cadence, and quality attributes that power a searchable catalog, enabling discovery and trust.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption at rest</b>: encryption protects stored data confidentiality but provides no discovery tags.</span><span class='qd'><b>Stress testing</b>: stress testing measures system behavior under load, not catalog discoverability.</span><span class='qd'><b>Backout planning</b>: a backout plan reverses a failed change and is unrelated to metadata tagging.</span>" },
{ id:"D5-013", domain:5, obj:"5.1", diff:"easy", q:"What is the PRIMARY purpose of maintaining a data dictionary in an organization?", options:["To provide a standard reference for field names, types, and meanings","To encrypt sensitive columns automatically","To schedule when data is destroyed","To balance the answer key of a quiz"], answer:0, explain:"<strong>To provide a standard reference for field names, types, and meanings</strong> is the core purpose of a data dictionary, promoting shared understanding and consistency.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To encrypt sensitive columns automatically</b>: a dictionary documents fields; it does not perform encryption.</span><span class='qd'><b>To schedule when data is destroyed</b>: destruction timing belongs to a retention schedule, not a dictionary.</span><span class='qd'><b>To balance the answer key of a quiz</b>: this is unrelated to data governance documentation.</span>" },
{ id:"D5-014", domain:5, obj:"5.1", diff:"medium", q:"During an MDM initiative, the team finds the same customer stored as 'Jon Smith,' 'J. Smith,' and 'Jonathan Smith' across systems. Which MDM activity resolves these into one golden record?", options:["Data encryption","Role assignment","Stress testing","Entity resolution and matching"], answer:3, explain:"<strong>Entity resolution and matching</strong> identifies records that refer to the same real-world entity and merges them into a single golden record, resolving the duplicate customer variants.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data encryption</b>: encryption secures values but does not merge duplicate entities.</span><span class='qd'><b>Role assignment</b>: assigning roles manages access, not record matching.</span><span class='qd'><b>Stress testing</b>: stress testing checks performance, not entity deduplication.</span>" },
{ id:"D5-015", domain:5, obj:"5.1", diff:"hard", q:"An ML governance reviewer rejects a deployed model because no one can describe which features influenced its predictions or trace the training data back to its sources. Which TWO governance gaps does this MOST directly reflect?", options:["Lack of explainability and lack of data lineage","Lack of encryption and lack of retention","Lack of RBAC and lack of masking","Lack of replication and lack of versioning"], answer:0, explain:"<strong>Lack of explainability and lack of data lineage</strong> is correct: inability to describe influential features is an explainability gap, and inability to trace training data to its sources is a lineage gap.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Lack of encryption and lack of retention</b>: encryption and retention concern protection and storage duration, not interpretability or provenance.</span><span class='qd'><b>Lack of RBAC and lack of masking</b>: access control and masking address security, not model transparency or data tracing.</span><span class='qd'><b>Lack of replication and lack of versioning</b>: replication and versioning concern copies and history, not feature influence or source tracing.</span>" },
{ id:"D5-016", domain:5, obj:"5.1", diff:"medium", q:"A reporting team wants nightly point-in-time copies of the warehouse so end-of-day figures never change after capture, while keeping a live table for current activity. The nightly copies are BEST described as:", options:["Indexes","Snapshots","Honeytokens","Surrogate keys"], answer:1, explain:"<strong>Snapshots</strong> are point-in-time captures of data that remain fixed after creation, ideal for stable end-of-day reporting alongside a live table.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Indexes</b>: an index speeds query lookups; it is not a point-in-time copy.</span><span class='qd'><b>Honeytokens</b>: honeytokens are decoy data used to detect intruders, not reporting copies.</span><span class='qd'><b>Surrogate keys</b>: a surrogate key is an artificial unique identifier, not a data snapshot.</span>" },
{ id:"D5-017", domain:5, obj:"5.1", diff:"easy", q:"Which artifact would an analyst consult to understand the chain of systems and transformations a dataset has passed through?", options:["Color palette guide","Confusion matrix","Maintenance window","Data lineage"], answer:3, explain:"<strong>Data lineage</strong> documents the chain of systems and transformations a dataset has passed through from origin to its current form.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Color palette guide</b>: a color guide governs visualization styling, not data provenance.</span><span class='qd'><b>Confusion matrix</b>: a confusion matrix evaluates classification model performance, not data flow.</span><span class='qd'><b>Maintenance window</b>: a maintenance window is a scheduled change period, unrelated to dataset history.</span>" },
{ id:"D5-018", domain:5, obj:"5.1", diff:"medium", q:"A company designates its ERP as authoritative for product master data and configures the warehouse and storefront to pull product records from it. This pattern enforces which principle?", options:["Data drift","Eventual deletion","Stress testing","Single source of truth"], answer:3, explain:"<strong>Single source of truth</strong> is enforced when one authoritative system (the ERP) supplies product records that all other systems consume, preventing conflicting versions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data drift</b>: drift describes statistical change in data over time, not authoritative sourcing.</span><span class='qd'><b>Eventual deletion</b>: deletion concerns removing data, not designating authority.</span><span class='qd'><b>Stress testing</b>: stress testing assesses load handling, not data authority.</span>" },
{ id:"D5-019", domain:5, obj:"5.1", diff:"hard", q:"An organization wants metadata to capture not just technical details (data types, sizes) but also business context (definitions, owners, stewardship). Adding the second category is referred to as which type of metadata?", options:["Operational metadata","Physical metadata","Volatile metadata","Business metadata"], answer:3, explain:"<strong>Business metadata</strong> captures business-facing context such as definitions, ownership, and stewardship, complementing technical metadata like data types and sizes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Operational metadata</b>: operational metadata records run statistics like job timing and row counts, not business definitions.</span><span class='qd'><b>Physical metadata</b>: physical metadata describes storage details, which is technical, not business context.</span><span class='qd'><b>Volatile metadata</b>: this is not a standard metadata category.</span>" },
{ id:"D5-020", domain:5, obj:"5.1", diff:"medium", q:"A team replaces a brittle manual export-and-paste process with a scheduled pipeline that pulls from APIs, harmonizes formats, and loads a central store automatically. This improvement BEST exemplifies maturing which capability?", options:["Data destruction","Data integration","Pseudonymization","Penetration testing"], answer:1, explain:"<strong>Data integration</strong> is matured when manual exports are replaced by automated, scheduled pipelines that pull, harmonize, and load data from multiple sources into a central store.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data destruction</b>: destruction is the secure removal of data, not consolidation.</span><span class='qd'><b>Pseudonymization</b>: pseudonymization swaps identifiers for tokens, unrelated to pipeline automation.</span><span class='qd'><b>Penetration testing</b>: pen testing probes for vulnerabilities, not data consolidation.</span>" },
{ id:"D5-021", domain:5, obj:"5.2", diff:"easy", q:"A policy states that customer transaction records must be kept for seven years and then securely destroyed. This policy is an example of:", options:["An access control list","A data dictionary","A retention schedule","A confusion matrix"], answer:2, explain:"<strong>A retention schedule</strong> defines how long each data type must be kept and when it must be destroyed, exactly as the seven-year transaction rule describes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An access control list</b>: an ACL lists who may access a resource, not how long data is kept.</span><span class='qd'><b>A data dictionary</b>: a dictionary defines fields, not retention periods.</span><span class='qd'><b>A confusion matrix</b>: a confusion matrix evaluates model accuracy, unrelated to retention.</span>" },
{ id:"D5-022", domain:5, obj:"5.2", diff:"medium", q:"A European customer asks a company to delete all personal data it holds about them. Which regulation grants this 'right to erasure'?", options:["PCI DSS","HIPAA Security Rule","GDPR","ISO 9001"], answer:2, explain:"<strong>GDPR</strong> grants EU data subjects the right to erasure (right to be forgotten), allowing them to request deletion of their personal data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>PCI DSS</b>: PCI DSS governs payment card data security and does not provide a general erasure right.</span><span class='qd'><b>HIPAA Security Rule</b>: HIPAA protects U.S. health information and has no broad right-to-erasure provision like GDPR.</span><span class='qd'><b>ISO 9001</b>: ISO 9001 is a quality-management standard, not a privacy regulation.</span>" },
{ id:"D5-023", domain:5, obj:"5.2", diff:"medium", q:"A retailer that stores and processes credit card numbers must comply with which standard governing cardholder data security?", options:["GDPR","COBIT","PCI DSS","ISO 14001"], answer:2, explain:"<strong>PCI DSS</strong> (Payment Card Industry Data Security Standard) sets requirements for organizations that store, process, or transmit cardholder data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>GDPR</b>: GDPR governs EU personal data broadly, not the specific card-security controls PCI DSS mandates.</span><span class='qd'><b>COBIT</b>: COBIT is an IT governance framework, not a cardholder-data security standard.</span><span class='qd'><b>ISO 14001</b>: ISO 14001 concerns environmental management, unrelated to payment data.</span>" },
{ id:"D5-024", domain:5, obj:"5.2", diff:"hard", q:"A U.S. company stores EU residents' data in a U.S. data center, but EU law restricts where that data may reside and how it crosses borders. This situation is BEST described as a challenge of:", options:["Data drift","Stress testing","Data hierarchy","Jurisdictional requirements"], answer:3, explain:"<strong>Jurisdictional requirements</strong> govern where data may legally reside and how it may cross borders, which is exactly the cross-border EU-to-U.S. storage conflict described.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data drift</b>: drift is statistical change in data over time, not a legal residency issue.</span><span class='qd'><b>Stress testing</b>: stress testing measures performance, not legal compliance.</span><span class='qd'><b>Data hierarchy</b>: a hierarchy organizes data levels, unrelated to cross-border law.</span>" },
{ id:"D5-025", domain:5, obj:"5.2", diff:"medium", q:"After discovering attackers exfiltrated a customer table, the security team must notify regulators and affected individuals within a legally mandated timeframe. This obligation is known as:", options:["Breach notification","Data profiling","Backout planning","Data binning"], answer:0, explain:"<strong>Breach notification</strong> is the legal obligation to inform regulators and affected individuals within a mandated window after a data breach is discovered.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data profiling</b>: profiling examines data quality, not breach reporting.</span><span class='qd'><b>Backout planning</b>: a backout plan reverses a failed change, unrelated to notifying regulators.</span><span class='qd'><b>Data binning</b>: binning groups values into ranges, a preparation technique, not a compliance duty.</span>" },
{ id:"D5-026", domain:5, obj:"5.2", diff:"easy", q:"Labeling datasets as Public, Internal, Confidential, or Restricted based on sensitivity is an example of:", options:["Data classification","Data replication","Data versioning","Data sampling"], answer:0, explain:"<strong>Data classification</strong> assigns sensitivity labels such as Public, Internal, Confidential, or Restricted so appropriate controls can be applied.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data replication</b>: replication copies data across locations, not labeling sensitivity.</span><span class='qd'><b>Data versioning</b>: versioning tracks change history, not sensitivity tiers.</span><span class='qd'><b>Data sampling</b>: sampling selects a subset for analysis, unrelated to classification.</span>" },
{ id:"D5-027", domain:5, obj:"5.2", diff:"medium", q:"A marketing team wants to buy a list of customers' personal data and resell their browsing habits without consent. The analyst objects on which grounds, even though it may be technically legal?", options:["Data normalization","Data ethics","Query optimization","Data binning"], answer:1, explain:"<strong>Data ethics</strong> concerns doing what is right with data beyond mere legality, such as respecting consent and not exploiting personal information, which underpins the analyst's objection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data normalization</b>: normalization is a database design technique, not an ethical principle.</span><span class='qd'><b>Query optimization</b>: optimization improves query speed, irrelevant to consent.</span><span class='qd'><b>Data binning</b>: binning groups numeric values, unrelated to ethics.</span>" },
{ id:"D5-028", domain:5, obj:"5.2", diff:"hard", q:"An organization keeps personal data for 'as long as it might be useful' with no defined end date. Which compliance risk does this MOST directly create under principles like GDPR's storage limitation?", options:["Excessive query load times","Over-retention of personal data beyond its lawful purpose","Loss of color accessibility","Data drift in a model"], answer:1, explain:"<strong>Over-retention of personal data beyond its lawful purpose</strong> is the risk: storage-limitation principles require keeping personal data only as long as needed, so indefinite retention violates them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Excessive query load times</b>: this is a performance issue, not a retention-compliance risk.</span><span class='qd'><b>Loss of color accessibility</b>: accessibility concerns visualization design, not retention.</span><span class='qd'><b>Data drift in a model</b>: drift is a model-quality issue, unrelated to storage limitation.</span>" },
{ id:"D5-029", domain:5, obj:"5.2", diff:"medium", q:"To meet disaster-recovery and availability requirements, a bank copies its transaction database to a second region in near real time. Storing these copies in multiple locations is called:", options:["Data replication","Data masking","Data classification","Pseudonymization"], answer:0, explain:"<strong>Data replication</strong> maintains copies of data across multiple locations or regions to support availability and disaster recovery, as the bank's cross-region copying illustrates.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data masking</b>: masking obscures sensitive values, not copying data across regions.</span><span class='qd'><b>Data classification</b>: classification labels sensitivity, not creating copies.</span><span class='qd'><b>Pseudonymization</b>: pseudonymization replaces identifiers, unrelated to multi-region copies.</span>" },
{ id:"D5-030", domain:5, obj:"5.2", diff:"easy", q:"A formal, independent review that verifies whether an organization follows its data policies and regulatory obligations is called a(n):", options:["Snapshot","Histogram","Audit","Index"], answer:2, explain:"<strong>Audit</strong> is a formal, often independent review that verifies compliance with policies and regulations, providing assurance and identifying gaps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Snapshot</b>: a snapshot is a point-in-time data copy, not a compliance review.</span><span class='qd'><b>Histogram</b>: a histogram is a chart of distribution, not an audit.</span><span class='qd'><b>Index</b>: an index speeds queries, unrelated to compliance review.</span>" },
{ id:"D5-031", domain:5, obj:"5.2", diff:"medium", q:"A healthcare analyst must follow rules for protecting patient health information in the United States. Which framework MOST directly governs this?", options:["PCI DSS","GDPR","ISO 27017","HIPAA"], answer:3, explain:"<strong>HIPAA</strong> (Health Insurance Portability and Accountability Act) governs the protection of patient health information in the United States.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>PCI DSS</b>: PCI DSS covers payment card data, not health records.</span><span class='qd'><b>GDPR</b>: GDPR is the EU's general personal-data regulation, not the U.S. health-specific framework.</span><span class='qd'><b>ISO 27017</b>: ISO 27017 provides cloud security guidance, not U.S. health-data rules.</span>" },
{ id:"D5-032", domain:5, obj:"5.2", diff:"hard", q:"A global firm must satisfy GDPR for EU customers, CCPA for California residents, and PCI DSS for payments simultaneously. The BEST strategy to manage these overlapping obligations is to:", options:["Pick only the strictest one and ignore the rest","Build a unified controls framework that maps each requirement to shared controls","Store all data in one country to avoid the others","Disable auditing to reduce overhead"], answer:1, explain:"<strong>Build a unified controls framework that maps each requirement to shared controls</strong> lets the firm satisfy overlapping regulations efficiently by implementing common controls once and mapping them to each obligation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pick only the strictest one and ignore the rest</b>: one regulation rarely fully covers another's specific requirements, so this leaves gaps.</span><span class='qd'><b>Store all data in one country to avoid the others</b>: regulations apply based on data subjects and activities, not merely storage location, so this does not exempt the firm.</span><span class='qd'><b>Disable auditing to reduce overhead</b>: removing audits increases noncompliance risk rather than managing it.</span>" },
{ id:"D5-033", domain:5, obj:"5.2", diff:"medium", q:"Under GDPR, the party that determines the purposes and means of processing personal data is the:", options:["Data processor","Data subject","Data steward","Data controller"], answer:3, explain:"<strong>Data controller</strong> is the GDPR party that determines the purposes and means of processing personal data and bears primary accountability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data processor</b>: a processor acts on the controller's instructions and does not decide purposes and means.</span><span class='qd'><b>Data subject</b>: the data subject is the individual whose data is processed, not the decision-maker.</span><span class='qd'><b>Data steward</b>: a steward manages data quality operationally and is not the GDPR legal role determining processing purposes.</span>" },
{ id:"D5-034", domain:5, obj:"5.2", diff:"easy", q:"Securely overwriting or shredding storage media when its retention period expires is an example of:", options:["Data acquisition","Data augmentation","Data destruction","Data normalization"], answer:2, explain:"<strong>Data destruction</strong> is the secure, irreversible removal of data, such as overwriting or shredding media at the end of its retention period.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data acquisition</b>: acquisition is collecting data, the opposite of destroying it.</span><span class='qd'><b>Data augmentation</b>: augmentation adds derived data, not removal.</span><span class='qd'><b>Data normalization</b>: normalization restructures data for design, not destruction.</span>" },
{ id:"D5-035", domain:5, obj:"5.2", diff:"medium", q:"A compliance officer maps regulatory storage rules requiring some records on encrypted, geographically restricted servers. This concern is primarily about:", options:["Chart selection","Storage location and requirements","Confusion matrices","Surrogate keys"], answer:1, explain:"<strong>Storage location and requirements</strong> addresses where and how data must be stored, including encryption and geographic constraints, matching the officer's mapping task.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Chart selection</b>: choosing charts is a visualization concern, not storage compliance.</span><span class='qd'><b>Confusion matrices</b>: confusion matrices evaluate models, unrelated to storage rules.</span><span class='qd'><b>Surrogate keys</b>: surrogate keys are database identifiers, not storage-location requirements.</span>" },
{ id:"D5-036", domain:5, obj:"5.2", diff:"hard", q:"A SaaS provider replicates customer data to three regions for resilience, but one region is in a country whose laws conflict with a customer's GDPR obligations. What is the MOST appropriate governance response?", options:["Ignore it because replication improves availability","Delete all backups to avoid the conflict","Encrypt the dashboard color palette","Restrict replication so personal data stays within compliant jurisdictions"], answer:3, explain:"<strong>Restrict replication so personal data stays within compliant jurisdictions</strong> resolves the conflict by honoring data-residency law while still allowing resilient replication among lawful regions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore it because replication improves availability</b>: availability gains do not excuse violating jurisdictional law.</span><span class='qd'><b>Delete all backups to avoid the conflict</b>: deleting backups harms recoverability and is an overreaction; the issue is location, not existence.</span><span class='qd'><b>Encrypt the dashboard color palette</b>: this is nonsensical and addresses neither residency nor compliance.</span>" },
{ id:"D5-037", domain:5, obj:"5.2", diff:"medium", q:"Which U.S.-developed framework provides voluntary standards and guidance for managing cybersecurity and privacy risk, widely referenced in compliance programs?", options:["COPPA","SOX","NIST","Kanban"], answer:2, explain:"<strong>NIST</strong> (National Institute of Standards and Technology) publishes widely adopted frameworks and guidance for managing cybersecurity and privacy risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>COPPA</b>: COPPA is a narrow U.S. law protecting children's online data, not a broad risk framework.</span><span class='qd'><b>SOX</b>: SOX governs financial reporting controls, not a general cybersecurity standards body.</span><span class='qd'><b>Kanban</b>: Kanban is a workflow-management method, not a security framework.</span>" },
{ id:"D5-038", domain:5, obj:"5.2", diff:"easy", q:"What is the FIRST step typically required after a data breach is detected under most incident-reporting policies?", options:["Permanently delete all logs","Promptly report and document the incident through the defined process","Publicly post the raw data","Disable the audit trail"], answer:1, explain:"<strong>Promptly report and document the incident through the defined process</strong> is the correct first step, triggering the response workflow and preserving evidence and notifications.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Permanently delete all logs</b>: deleting logs destroys evidence and may itself violate law.</span><span class='qd'><b>Publicly post the raw data</b>: exposing the data worsens the breach.</span><span class='qd'><b>Disable the audit trail</b>: disabling auditing hides the incident and obstructs investigation.</span>" },
{ id:"D5-039", domain:5, obj:"5.2", diff:"medium", q:"An organization adopts an internationally recognized standard for an information security management system to demonstrate compliance to partners. Which standard is MOST likely chosen?", options:["ISO/IEC 27001","ISO 9001","HTTP/2","JPEG 2000"], answer:0, explain:"<strong>ISO/IEC 27001</strong> specifies requirements for an information security management system (ISMS) and is the standard organizations certify against to demonstrate security compliance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ISO 9001</b>: ISO 9001 addresses general quality management, not information security specifically.</span><span class='qd'><b>HTTP/2</b>: HTTP/2 is a web transfer protocol, not a security management standard.</span><span class='qd'><b>JPEG 2000</b>: JPEG 2000 is an image compression standard, unrelated to security management.</span>" },
{ id:"D5-040", domain:5, obj:"5.2", diff:"hard", q:"A breach exposes hashed-but-unsalted passwords, full names, and partial card numbers. To prioritize notification and remediation correctly, the team should FIRST:", options:["Rebuild the marketing dashboard","Classify the exposed data by sensitivity and regulatory scope","Re-run query optimization on the warehouse","Change the company logo color"], answer:1, explain:"<strong>Classify the exposed data by sensitivity and regulatory scope</strong> first determines which laws (such as PCI DSS for card numbers) and obligations apply, driving correct notification and remediation priorities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rebuild the marketing dashboard</b>: dashboards are irrelevant to breach triage.</span><span class='qd'><b>Re-run query optimization on the warehouse</b>: performance tuning does not address a breach.</span><span class='qd'><b>Change the company logo color</b>: branding has no bearing on incident response.</span>" },
{ id:"D5-041", domain:5, obj:"5.3", diff:"easy", q:"Granting users permissions based on their job function, such as 'Analyst' or 'Manager,' rather than per-individual, describes which access model?", options:["Role-based access control","Mandatory destruction","Data replication","Data binning"], answer:0, explain:"<strong>Role-based access control</strong> (RBAC) assigns permissions to roles tied to job functions, and users inherit access by their role, simplifying administration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Mandatory destruction</b>: this concerns deleting data, not granting access.</span><span class='qd'><b>Data replication</b>: replication copies data, unrelated to permission assignment.</span><span class='qd'><b>Data binning</b>: binning groups numeric values, not an access model.</span>" },
{ id:"D5-042", domain:5, obj:"5.3", diff:"medium", q:"A company encrypts traffic between users' browsers and its analytics portal using TLS. This protects data in which state?", options:["Data at rest","Data in use","Data in archive","Data in transit"], answer:3, explain:"<strong>Data in transit</strong> is data moving across a network, and TLS encrypts that traffic between browser and server to protect it from interception.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data at rest</b>: data at rest is stored data; TLS does not encrypt stored files.</span><span class='qd'><b>Data in use</b>: data in use is being actively processed in memory, which TLS does not protect.</span><span class='qd'><b>Data in archive</b>: archived data is a form of data at rest, not network traffic.</span>" },
{ id:"D5-043", domain:5, obj:"5.3", diff:"medium", q:"A database stores customer files on disks that are encrypted so that stolen drives reveal nothing. This protects data in which state?", options:["Data at rest","Data in transit","Data in motion","Data in use"], answer:0, explain:"<strong>Data at rest</strong> is stored data, and disk or database encryption protects it so stolen media yields no readable content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data in transit</b>: transit refers to data moving over a network, not stored on disk.</span><span class='qd'><b>Data in motion</b>: data in motion is another term for in transit, not at rest.</span><span class='qd'><b>Data in use</b>: data in use is being processed in memory, not stored on disk.</span>" },
{ id:"D5-044", domain:5, obj:"5.3", diff:"easy", q:"Names, Social Security numbers, and email addresses that can identify a specific person are categorized as:", options:["PII","KPI","ETL","SLA"], answer:0, explain:"<strong>PII</strong> (personally identifiable information) is any data that can identify a specific individual, such as name, SSN, or email address.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>KPI</b>: a KPI is a key performance indicator metric, not personal data.</span><span class='qd'><b>ETL</b>: ETL is a data integration process, not a data category.</span><span class='qd'><b>SLA</b>: an SLA is a service-level agreement, not identifying data.</span>" },
{ id:"D5-045", domain:5, obj:"5.3", diff:"medium", q:"A hospital dataset contains diagnoses tied to patient identities. This combination of health data with identifiers is classified as:", options:["Public data","Synthetic data","PHI","Metadata"], answer:2, explain:"<strong>PHI</strong> (protected health information) is health data linked to an identifiable individual, exactly the diagnosis-plus-identity combination described.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public data</b>: public data carries no sensitivity restrictions, unlike identified health records.</span><span class='qd'><b>Synthetic data</b>: synthetic data is artificially generated, not real patient records.</span><span class='qd'><b>Metadata</b>: metadata describes data attributes, not the patient health content itself.</span>" },
{ id:"D5-046", domain:5, obj:"5.3", diff:"medium", q:"To let developers test with realistic-looking data, an analyst replaces real card numbers with format-preserving fake values like XXXX-XXXX-XXXX-1234. This technique is:", options:["Data masking","Data replication","Data versioning","Data integration"], answer:0, explain:"<strong>Data masking</strong> substitutes sensitive values with realistic but fictional ones (such as obscured card numbers), letting non-production users work without exposing real data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data replication</b>: replication copies real data unchanged, which would still expose the card numbers.</span><span class='qd'><b>Data versioning</b>: versioning tracks change history, not obscuring values.</span><span class='qd'><b>Data integration</b>: integration combines sources, unrelated to hiding sensitive values.</span>" },
{ id:"D5-047", domain:5, obj:"5.3", diff:"hard", q:"An analyst removes names and direct identifiers and replaces each customer ID with a random token, keeping a separate secured key that can re-link tokens to people if needed. Which technique is this?", options:["Pseudonymization","Anonymization","Encryption in transit","RBAC"], answer:0, explain:"<strong>Pseudonymization</strong> replaces identifiers with tokens while retaining a separately protected key that can re-link the data, distinguishing it from irreversible anonymization.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Anonymization</b>: true anonymization is irreversible with no re-linking key, so the retained key makes this pseudonymization instead.</span><span class='qd'><b>Encryption in transit</b>: encryption in transit protects network traffic, not the substitution of identifiers in stored data.</span><span class='qd'><b>RBAC</b>: RBAC manages access permissions, not identifier replacement.</span>" },
{ id:"D5-048", domain:5, obj:"5.3", diff:"hard", q:"A research team must publish a dataset that can NEVER be re-linked to individuals, even by the team itself. Which technique BEST meets this requirement?", options:["Pseudonymization with a retained key","Irreversible anonymization","Role-based access control","TLS encryption"], answer:1, explain:"<strong>Irreversible anonymization</strong> permanently removes the ability to re-identify individuals, satisfying the requirement that no one, including the team, can re-link the data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pseudonymization with a retained key</b>: keeping a key leaves the data re-linkable, violating the never-re-link requirement.</span><span class='qd'><b>Role-based access control</b>: RBAC limits who can access data but does not make it impossible to re-identify.</span><span class='qd'><b>TLS encryption</b>: TLS protects data in transit and is reversible by authorized parties, so it does not prevent re-identification.</span>" },
{ id:"D5-049", domain:5, obj:"5.3", diff:"easy", q:"The principle of granting users only the minimum access needed to perform their job is called:", options:["Least privilege","Maximum exposure","Open access","Implicit trust"], answer:0, explain:"<strong>Least privilege</strong> grants each user only the minimum access necessary for their duties, reducing the risk and impact of compromise or misuse.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Maximum exposure</b>: this is the opposite of secure access design.</span><span class='qd'><b>Open access</b>: open access grants broad permissions, contradicting least privilege.</span><span class='qd'><b>Implicit trust</b>: implicit trust assumes access without verification, the opposite of the principle.</span>" },
{ id:"D5-050", domain:5, obj:"5.3", diff:"medium", q:"Two companies plan to exchange datasets and want a contract defining permitted uses, security obligations, and restrictions. This document is a:", options:["Color palette guide","Confusion matrix","Data sharing agreement","Backout plan"], answer:2, explain:"<strong>Data sharing agreement</strong> is a contract that defines how shared data may be used, the security obligations of each party, and any restrictions, exactly the inter-company exchange described.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Color palette guide</b>: a color guide governs visualization styling, not data exchange terms.</span><span class='qd'><b>Confusion matrix</b>: a confusion matrix evaluates model accuracy, unrelated to contracts.</span><span class='qd'><b>Backout plan</b>: a backout plan reverses a failed change, not a data-use contract.</span>" },
{ id:"D5-051", domain:5, obj:"5.3", diff:"medium", q:"A bank wants analysts to query aggregated trends but never see individual account holders' names. The BEST control to enforce this at the column level is:", options:["Masking or restricting the name column for analyst roles","Replicating the table to another region","Increasing the retention period","Adding more indexes"], answer:0, explain:"<strong>Masking or restricting the name column for analyst roles</strong> lets analysts see aggregates while hiding individual identities, enforcing privacy at the column level.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replicating the table to another region</b>: replication copies data without restricting who sees names.</span><span class='qd'><b>Increasing the retention period</b>: retention affects how long data is kept, not who can view names.</span><span class='qd'><b>Adding more indexes</b>: indexes improve performance, not privacy.</span>" },
{ id:"D5-052", domain:5, obj:"5.3", diff:"hard", q:"An organization wants access decisions to consider attributes like department, project, clearance, and time of day, beyond a static role. Which model BEST supports this fine-grained, context-aware access?", options:["Role-based access control alone","Discretionary deletion","Static IP allow listing","Attribute-based access control"], answer:3, explain:"<strong>Attribute-based access control</strong> (ABAC) evaluates multiple attributes such as department, project, clearance, and time to make fine-grained, context-aware decisions beyond a fixed role.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Role-based access control alone</b>: RBAC keys solely on role and cannot natively factor dynamic context like time of day.</span><span class='qd'><b>Discretionary deletion</b>: this is not an access model; it concerns removing data.</span><span class='qd'><b>Static IP allow listing</b>: allow listing filters by IP only, not rich user and context attributes.</span>" },
{ id:"D5-053", domain:5, obj:"5.3", diff:"easy", q:"Which framework is commonly referenced for privacy and security control guidance, including its widely used Privacy Framework and SP 800-series publications?", options:["FIFO","NIST","CSV","DPI"], answer:1, explain:"<strong>NIST</strong> publishes the Privacy Framework and the SP 800-series, widely referenced for privacy and security control guidance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FIFO</b>: FIFO is a queue/inventory ordering method, not a privacy framework.</span><span class='qd'><b>CSV</b>: CSV is a file format, not a guidance framework.</span><span class='qd'><b>DPI</b>: DPI (dots per inch or deep packet inspection) is unrelated to privacy frameworks.</span>" },
{ id:"D5-054", domain:5, obj:"5.3", diff:"medium", q:"A vendor contract permits using shared customer data only for fraud detection, not marketing. Honoring this constraint is an example of governing:", options:["Data binning","Chart selection","Data usage and sharing","Query indexing"], answer:2, explain:"<strong>Data usage and sharing</strong> governs the permitted purposes for which data may be used or shared, such as restricting vendor data to fraud detection only.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data binning</b>: binning groups numeric values, not governing use restrictions.</span><span class='qd'><b>Chart selection</b>: chart choice is a visualization concern, unrelated to usage rights.</span><span class='qd'><b>Query indexing</b>: indexing improves performance, not data-use governance.</span>" },
{ id:"D5-055", domain:5, obj:"5.3", diff:"medium", q:"An employee changes from the Finance team to Marketing but keeps all old Finance permissions in addition to new ones. Over time this accumulation of unnecessary rights is called:", options:["Least privilege","Privilege creep","Data drift","Pseudonymization"], answer:1, explain:"<strong>Privilege creep</strong> is the gradual accumulation of access rights beyond what a role needs, often from role changes, increasing risk and violating least privilege.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Least privilege</b>: least privilege is the goal being violated, not the accumulation itself.</span><span class='qd'><b>Data drift</b>: drift concerns changing data statistics, not access rights.</span><span class='qd'><b>Pseudonymization</b>: pseudonymization replaces identifiers, unrelated to permissions.</span>" },
{ id:"D5-056", domain:5, obj:"5.3", diff:"hard", q:"A company shares a 'de-identified' dataset, but an attacker combines it with a public voter list to re-identify individuals. This attack exploits the weakness of:", options:["Excessive encryption strength","Too many database indexes","Insufficient anonymization vulnerable to linkage attacks","Overly strict RBAC"], answer:2, explain:"<strong>Insufficient anonymization vulnerable to linkage attacks</strong> is the weakness: when removed identifiers leave quasi-identifiers, combining the data with external sources can re-identify people.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Excessive encryption strength</b>: strong encryption does not enable re-identification; the issue is weak anonymization.</span><span class='qd'><b>Too many database indexes</b>: indexes affect performance, not re-identification risk.</span><span class='qd'><b>Overly strict RBAC</b>: strict access control would reduce exposure, not cause re-identification.</span>" },
{ id:"D5-057", domain:5, obj:"5.3", diff:"medium", q:"To verify a user's identity before granting database access, a system requires a password plus a code from an authenticator app. This is an example of:", options:["Data masking","Data replication","Data classification","Multifactor authentication"], answer:3, explain:"<strong>Multifactor authentication</strong> combines two or more independent factors, such as a password (knowledge) and an authenticator code (possession), strengthening identity verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data masking</b>: masking obscures data values, not verifying identity.</span><span class='qd'><b>Data replication</b>: replication copies data, unrelated to authentication.</span><span class='qd'><b>Data classification</b>: classification labels sensitivity, not user verification.</span>" },
{ id:"D5-058", domain:5, obj:"5.3", diff:"easy", q:"Which technique converts readable data into ciphertext that requires a key to decode?", options:["Aggregation","Binning","Normalization","Encryption"], answer:3, explain:"<strong>Encryption</strong> transforms readable plaintext into ciphertext that can only be decoded with the correct key, protecting confidentiality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Aggregation</b>: aggregation summarizes data, not encoding it with a key.</span><span class='qd'><b>Binning</b>: binning groups values into ranges, not protecting confidentiality.</span><span class='qd'><b>Normalization</b>: normalization restructures data for design or scaling, not encoding.</span>" },
{ id:"D5-059", domain:5, obj:"5.3", diff:"hard", q:"A team must protect highly sensitive PHI both while it sits in the cloud database and while it travels to a reporting app. Which combination of controls is MOST appropriate?", options:["Only changing the chart colors","Only increasing the retention period","Only adding more indexes","Encryption at rest plus encryption in transit"], answer:3, explain:"<strong>Encryption at rest plus encryption in transit</strong> protects PHI both while stored in the database and while moving across the network, addressing both states.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only changing the chart colors</b>: visualization styling provides no data protection.</span><span class='qd'><b>Only increasing the retention period</b>: retention concerns how long data is kept, not its confidentiality.</span><span class='qd'><b>Only adding more indexes</b>: indexes improve speed, not security.</span>" },
{ id:"D5-060", domain:5, obj:"5.3", diff:"medium", q:"An organization periodically reviews who has access to sensitive datasets and revokes rights no longer needed. This recurring practice is called a(n):", options:["Data snapshot","Stress test","Access review (recertification)","Histogram analysis"], answer:2, explain:"<strong>Access review (recertification)</strong> periodically validates that users' access is still appropriate and revokes unneeded rights, countering privilege creep.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data snapshot</b>: a snapshot is a point-in-time data copy, not an access review.</span><span class='qd'><b>Stress test</b>: a stress test measures performance under load, not access appropriateness.</span><span class='qd'><b>Histogram analysis</b>: a histogram shows distributions, unrelated to access governance.</span>" },
{ id:"D5-061", domain:5, obj:"5.4", diff:"easy", q:"Examining a dataset to summarize its structure, value ranges, null counts, and patterns before use is known as:", options:["Data masking","Data profiling","Data replication","Data destruction"], answer:1, explain:"<strong>Data profiling</strong> inspects a dataset to summarize structure, value ranges, null counts, and patterns, revealing quality issues before the data is used.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data masking</b>: masking hides sensitive values, not summarizing data characteristics.</span><span class='qd'><b>Data replication</b>: replication copies data, not analyzing its quality.</span><span class='qd'><b>Data destruction</b>: destruction removes data, the opposite of inspecting it.</span>" },
{ id:"D5-062", domain:5, obj:"5.4", diff:"medium", q:"A model's accuracy slowly declines because customer behavior has shifted and the live data no longer resembles the training data. This phenomenon is:", options:["Data masking","Data replication","Data drift","Data classification"], answer:2, explain:"<strong>Data drift</strong> occurs when the statistical properties of live data diverge from the training data over time, degrading model accuracy as behavior shifts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data masking</b>: masking obscures values and does not describe statistical change.</span><span class='qd'><b>Data replication</b>: replication copies data, unrelated to distribution change.</span><span class='qd'><b>Data classification</b>: classification labels sensitivity, not changing distributions.</span>" },
{ id:"D5-063", domain:5, obj:"5.4", diff:"medium", q:"Before users accept a new sales dashboard, business stakeholders test it against real-world scenarios to confirm it meets their needs. This phase is:", options:["Unit testing","User acceptance testing","Stress testing","Penetration testing"], answer:1, explain:"<strong>User acceptance testing</strong> (UAT) has business stakeholders validate that a solution meets their real-world requirements before final acceptance, matching the dashboard sign-off described.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Unit testing</b>: unit testing checks individual code components, not end-user business acceptance.</span><span class='qd'><b>Stress testing</b>: stress testing pushes a system to its performance limits, not validating business needs.</span><span class='qd'><b>Penetration testing</b>: pen testing probes security vulnerabilities, not user acceptance.</span>" },
{ id:"D5-064", domain:5, obj:"5.4", diff:"medium", q:"A developer writes small tests that verify a single transformation function returns the correct output for given inputs. These tests are:", options:["User acceptance tests","Stress tests","Unit tests","Requirement tests"], answer:2, explain:"<strong>Unit tests</strong> verify the correctness of individual functions or components in isolation, exactly the single-transformation checks described.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>User acceptance tests</b>: UAT validates whole-solution business fit, not an isolated function.</span><span class='qd'><b>Stress tests</b>: stress tests measure behavior under heavy load, not single-function correctness.</span><span class='qd'><b>Requirement tests</b>: requirement testing checks that stated requirements are met overall, broader than one function.</span>" },
{ id:"D5-065", domain:5, obj:"5.4", diff:"medium", q:"Before a quarterly close, a pipeline runs a scheduled job that checks row counts, null rates, and value ranges and alerts the team if any metric falls outside thresholds. This is BEST described as:", options:["Automated data quality monitoring","Manual chart styling","Data destruction","Pseudonymization"], answer:0, explain:"<strong>Automated data quality monitoring</strong> continuously or on a schedule checks metrics like row counts, null rates, and ranges and alerts on threshold breaches, exactly the described job.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manual chart styling</b>: styling charts is a visualization task, not quality monitoring.</span><span class='qd'><b>Data destruction</b>: destruction removes data, unrelated to monitoring quality.</span><span class='qd'><b>Pseudonymization</b>: pseudonymization swaps identifiers, not checking data metrics.</span>" },
{ id:"D5-066", domain:5, obj:"5.4", diff:"hard", q:"A data engineer wants to load-test a new ETL pipeline by feeding it ten times the normal daily volume to ensure it does not fail at peak. Which testing type is this?", options:["Stress testing","Unit testing","User acceptance testing","Requirement testing"], answer:0, explain:"<strong>Stress testing</strong> pushes a system beyond normal load (such as ten times daily volume) to confirm it performs or fails gracefully at peak, matching the engineer's goal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Unit testing</b>: unit testing checks small code units, not whole-pipeline load capacity.</span><span class='qd'><b>User acceptance testing</b>: UAT validates business requirements, not performance under extreme volume.</span><span class='qd'><b>Requirement testing</b>: requirement testing confirms stated requirements, not stress at peak load.</span>" },
{ id:"D5-067", domain:5, obj:"5.4", diff:"easy", q:"A team uses Git to track every change to its SQL and Python scripts, allowing rollback to prior versions. This practice is:", options:["Data masking","Data replication","Source control","Data classification"], answer:2, explain:"<strong>Source control</strong> (version control) like Git tracks every change to code, enabling history, collaboration, and rollback to prior versions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data masking</b>: masking obscures sensitive values, not tracking code changes.</span><span class='qd'><b>Data replication</b>: replication copies data across locations, not versioning code.</span><span class='qd'><b>Data classification</b>: classification labels data sensitivity, unrelated to code history.</span>" },
{ id:"D5-068", domain:5, obj:"5.4", diff:"medium", q:"A monthly routine compares current dataset quality metrics against expected baselines to confirm the data is still trustworthy. This routine is commonly called a:", options:["Backout plan","Confusion matrix","Data health check","Color audit"], answer:2, explain:"<strong>Data health check</strong> periodically compares quality metrics against baselines to confirm the data remains accurate, complete, and trustworthy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Backout plan</b>: a backout plan reverses a failed change, not assessing data quality.</span><span class='qd'><b>Confusion matrix</b>: a confusion matrix evaluates classification models, not dataset health.</span><span class='qd'><b>Color audit</b>: a color audit reviews visualization palettes, unrelated to data quality.</span>" },
{ id:"D5-069", domain:5, obj:"5.4", diff:"medium", q:"Before building a report, the team documents exactly what the business needs the report to calculate and display, then later verifies the report against those statements. Verifying against those statements is:", options:["Stress testing","Penetration testing","Unit testing","Requirement testing"], answer:3, explain:"<strong>Requirement testing</strong> verifies that a deliverable satisfies the documented business requirements, matching the report-versus-requirements check described.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stress testing</b>: stress testing measures performance under load, not requirement conformance.</span><span class='qd'><b>Penetration testing</b>: pen testing probes security, not requirement satisfaction.</span><span class='qd'><b>Unit testing</b>: unit testing checks isolated code units, narrower than verifying the report meets business requirements.</span>" },
{ id:"D5-070", domain:5, obj:"5.4", diff:"hard", q:"An automated monitor flags that a feeder system began sending dates as text instead of true date values, threatening downstream reports. This early warning of a changed input format is MOST valuable because it enables the team to:", options:["Increase the retention period automatically","Detect and remediate a data quality issue before it corrupts reports","Improve the dashboard color scheme","Anonymize the affected records"], answer:1, explain:"<strong>Detect and remediate a data quality issue before it corrupts reports</strong> is the value of automated monitoring: catching the format change early prevents bad data from propagating into reports.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase the retention period automatically</b>: retention is unrelated to fixing a format problem.</span><span class='qd'><b>Improve the dashboard color scheme</b>: styling does not address corrupted input data.</span><span class='qd'><b>Anonymize the affected records</b>: anonymization protects privacy, not data correctness.</span>" },
{ id:"D5-071", domain:5, obj:"5.4", diff:"easy", q:"Which international standard family is commonly associated with quality management systems that organizations adopt to standardize processes?", options:["HTTP","ISO 9000 series","JPEG","MP3"], answer:1, explain:"<strong>ISO 9000 series</strong> defines quality management system standards (including ISO 9001) that organizations adopt to standardize and improve processes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>HTTP</b>: HTTP is a web protocol, not a quality standard.</span><span class='qd'><b>JPEG</b>: JPEG is an image format, not a management standard.</span><span class='qd'><b>MP3</b>: MP3 is an audio format, unrelated to quality management.</span>" },
{ id:"D5-072", domain:5, obj:"5.4", diff:"medium", q:"During profiling, an analyst finds a 'state' column contains values like 'CA,' 'Calif.,' and 'California.' This finding primarily indicates a problem with which data quality dimension?", options:["Consistency","Encryption strength","Retention period","Replication count"], answer:0, explain:"<strong>Consistency</strong> is the dimension violated when the same concept is represented in conflicting formats like 'CA,' 'Calif.,' and 'California,' undermining reliable analysis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption strength</b>: encryption concerns confidentiality, not value uniformity.</span><span class='qd'><b>Retention period</b>: retention is about how long data is kept, not format uniformity.</span><span class='qd'><b>Replication count</b>: replication concerns copies, not consistent representation.</span>" },
{ id:"D5-073", domain:5, obj:"5.4", diff:"hard", q:"A pipeline passes unit tests but fails after deployment because an upstream schema changed silently. To catch such issues earlier, the team should add:", options:["Brighter dashboard colors","A longer retention policy","Automated schema and data validation checks in the pipeline","More aggressive data deletion"], answer:2, explain:"<strong>Automated schema and data validation checks in the pipeline</strong> would detect silent upstream schema changes at runtime, catching the failure before it reaches reports.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Brighter dashboard colors</b>: styling cannot detect schema changes.</span><span class='qd'><b>A longer retention policy</b>: retention affects storage duration, not change detection.</span><span class='qd'><b>More aggressive data deletion</b>: deleting data does not detect or prevent schema drift.</span>" },
{ id:"D5-074", domain:5, obj:"5.4", diff:"medium", q:"A team merges code changes into a shared repository several times a day, with automated tests running on each merge to catch breakage quickly. This practice is:", options:["Data anonymization","Data replication","Data binning","Continuous integration"], answer:3, explain:"<strong>Continuous integration</strong> frequently merges code into a shared repository with automated tests on each merge, catching defects early in development.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data anonymization</b>: anonymization removes identifiers, unrelated to code merging.</span><span class='qd'><b>Data replication</b>: replication copies data, not integrating code changes.</span><span class='qd'><b>Data binning</b>: binning groups numeric values, not a development practice.</span>" },
{ id:"D5-075", domain:5, obj:"5.4", diff:"easy", q:"What is the PRIMARY goal of quality assurance in a data project?", options:["To delete data as quickly as possible","To encrypt all dashboards","To maximize the number of indexes","To ensure data and deliverables meet defined standards and are fit for use"], answer:3, explain:"<strong>To ensure data and deliverables meet defined standards and are fit for use</strong> is the core goal of quality assurance, building trust in the outputs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To delete data as quickly as possible</b>: rapid deletion is a destruction concern, not quality assurance.</span><span class='qd'><b>To encrypt all dashboards</b>: encryption is a security control, not the purpose of QA.</span><span class='qd'><b>To maximize the number of indexes</b>: indexing is a performance tactic, not a QA objective.</span>" },
{ id:"D5-076", domain:5, obj:"5.4", diff:"hard", q:"An organization wants confidence that a critical nightly report is correct without a human reviewing it each morning. The MOST sustainable approach is to:", options:["Email the raw table to everyone daily","Implement automated monitoring with quality thresholds and alerts","Manually eyeball the dashboard occasionally","Disable testing to save time"], answer:1, explain:"<strong>Implement automated monitoring with quality thresholds and alerts</strong> sustainably validates the report nightly and notifies the team only when metrics breach thresholds, removing reliance on manual checks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Email the raw table to everyone daily</b>: distributing raw data does not validate correctness.</span><span class='qd'><b>Manually eyeball the dashboard occasionally</b>: occasional manual review is unreliable and not sustainable for a critical report.</span><span class='qd'><b>Disable testing to save time</b>: removing testing increases the chance of undetected errors.</span>" },
{ id:"D5-077", domain:5, obj:"5.4", diff:"medium", q:"A profiling report shows 18% of the 'email' column is blank. Which data quality dimension does this MOST directly measure?", options:["Completeness","Timeliness","Encryption","Replication"], answer:0, explain:"<strong>Completeness</strong> measures whether required values are present, so an 18% blank rate in the email column is a completeness problem.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Timeliness</b>: timeliness concerns how current data is, not whether values are missing.</span><span class='qd'><b>Encryption</b>: encryption is a security control, not a measure of missing values.</span><span class='qd'><b>Replication</b>: replication concerns copies across locations, not blank fields.</span>" },
{ id:"D5-078", domain:5, obj:"5.4", diff:"medium", q:"After a model degrades in production, the MLOps team sets up monitoring that compares the distribution of incoming features to the training set each week. The primary purpose is to detect:", options:["Privilege creep","Data drift","Tailgating","Index fragmentation"], answer:1, explain:"<strong>Data drift</strong> is detected by comparing incoming feature distributions to the training set over time, alerting the team when inputs diverge and degrade the model.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Privilege creep</b>: privilege creep is an access-rights accumulation issue, not a data distribution change.</span><span class='qd'><b>Tailgating</b>: tailgating is a physical security threat, unrelated to model inputs.</span><span class='qd'><b>Index fragmentation</b>: fragmentation is a storage performance issue, not feature distribution change.</span>" },
{ id:"D5-079", domain:5, obj:"5.4", diff:"hard", q:"A team wants every dataset version, transformation script, and test result tied together so any published number can be reproduced and audited. The BEST foundation for this reproducibility is:", options:["Only changing chart colors","Combining source control for code with data versioning and logged test results","Only deleting old datasets","Only increasing dashboard refresh rate"], answer:1, explain:"<strong>Combining source control for code with data versioning and logged test results</strong> ties code, data states, and validation evidence together, enabling any published number to be reproduced and audited.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only changing chart colors</b>: styling has no effect on reproducibility.</span><span class='qd'><b>Only deleting old datasets</b>: deleting history destroys the ability to reproduce prior results.</span><span class='qd'><b>Only increasing dashboard refresh rate</b>: refresh frequency does not provide reproducibility or audit trails.</span>" },
{ id:"D5-080", domain:5, obj:"5.4", diff:"easy", q:"Which testing type specifically validates that the system meets stakeholders' real-world needs before go-live?", options:["User acceptance testing","Unit testing","Stress testing","Penetration testing"], answer:0, explain:"<strong>User acceptance testing</strong> confirms with stakeholders that the system meets their real-world needs before go-live, serving as the final validation gate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Unit testing</b>: unit testing checks isolated code components, not overall stakeholder acceptance.</span><span class='qd'><b>Stress testing</b>: stress testing assesses performance under load, not business fit.</span><span class='qd'><b>Penetration testing</b>: pen testing evaluates security, not user acceptance.</span>" },
{ id:"D5-081", domain:5, obj:"5.1", diff:"medium", q:"A governance team wants every report to link back to documented definitions so two analysts always interpret 'active customer' identically. Which artifact MOST directly standardizes such business definitions?", options:["Business glossary / data dictionary","Stress test plan","Encryption policy","Replication schedule"], answer:0, explain:"<strong>Business glossary / data dictionary</strong> records agreed business definitions (such as what 'active customer' means) so analysts interpret terms consistently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stress test plan</b>: a stress test plan addresses performance, not term definitions.</span><span class='qd'><b>Encryption policy</b>: an encryption policy governs confidentiality, not shared definitions.</span><span class='qd'><b>Replication schedule</b>: a replication schedule governs copying, not business meaning.</span>" },
{ id:"D5-082", domain:5, obj:"5.1", diff:"hard", q:"A regulator demands proof that a flagged figure was not altered between the source system and the published report. Which combination BEST provides this assurance?", options:["Brighter colors plus a new font","More indexes plus a faster refresh","Masking plus a longer retention period","Data lineage plus versioned snapshots of each stage"], answer:3, explain:"<strong>Data lineage plus versioned snapshots of each stage</strong> documents the figure's path and preserves its exact value at each stage, proving it was not altered between source and report.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Brighter colors plus a new font</b>: styling provides no provenance assurance.</span><span class='qd'><b>More indexes plus a faster refresh</b>: performance tuning does not document data history.</span><span class='qd'><b>Masking plus a longer retention period</b>: masking hides values and retention keeps data longer, but neither traces transformations.</span>" },
{ id:"D5-083", domain:5, obj:"5.2", diff:"medium", q:"A company classifies a dataset as 'Restricted' and applies the strictest handling controls. The PRIMARY benefit of formal classification is that it:", options:["Speeds up SQL joins automatically","Eliminates the need for backups","Removes all access logging","Drives appropriate, consistent controls based on sensitivity"], answer:3, explain:"<strong>Drives appropriate, consistent controls based on sensitivity</strong> is the primary benefit: classification labels let the organization apply protection proportional to risk uniformly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Speeds up SQL joins automatically</b>: classification has no effect on query performance.</span><span class='qd'><b>Eliminates the need for backups</b>: backups remain essential regardless of classification.</span><span class='qd'><b>Removes all access logging</b>: classification supports, not removes, logging and oversight.</span>" },
{ id:"D5-084", domain:5, obj:"5.2", diff:"hard", q:"An organization processes EU personal data, U.S. health records, and card payments. A single missing control is discovered: no documented process to notify authorities after a breach. Which obligation is unmet across MULTIPLE of these regimes?", options:["Chart accessibility","Incident reporting / breach notification","Dashboard branding","Index optimization"], answer:1, explain:"<strong>Incident reporting / breach notification</strong> is required by GDPR, HIPAA, and PCI-related rules alike, so a missing notification process violates obligations across all three regimes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Chart accessibility</b>: accessibility concerns visualization, not breach reporting law.</span><span class='qd'><b>Dashboard branding</b>: branding is cosmetic and not a regulatory obligation.</span><span class='qd'><b>Index optimization</b>: indexing is a performance task, unrelated to breach notification.</span>" },
{ id:"D5-085", domain:5, obj:"5.3", diff:"medium", q:"A startup gives every employee admin rights to the data warehouse for convenience. A security reviewer flags this as a violation of which principle?", options:["Data lineage","Data versioning","Stress testing","Least privilege"], answer:3, explain:"<strong>Least privilege</strong> is violated when everyone receives broad admin rights, because users should have only the minimum access their job requires.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data lineage</b>: lineage traces data movement, not access scope.</span><span class='qd'><b>Data versioning</b>: versioning tracks data history, unrelated to permissions.</span><span class='qd'><b>Stress testing</b>: stress testing measures load handling, not access rights.</span>" },
{ id:"D5-086", domain:5, obj:"5.3", diff:"hard", q:"An analytics vendor will receive a customer dataset. To minimize privacy risk while preserving analytic value, the BEST first step is to:", options:["Send the raw data and trust the contract alone","Pseudonymize or mask direct identifiers before sharing","Email the data unencrypted for speed","Grant the vendor admin access to the source database"], answer:1, explain:"<strong>Pseudonymize or mask direct identifiers before sharing</strong> reduces exposure of personal data while keeping the dataset useful for analysis, applying privacy by design.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Send the raw data and trust the contract alone</b>: a contract alone does not technically reduce the exposure of identifiers.</span><span class='qd'><b>Email the data unencrypted for speed</b>: unencrypted email exposes data in transit, increasing risk.</span><span class='qd'><b>Grant the vendor admin access to the source database</b>: broad access violates least privilege and exposes far more than necessary.</span>" },
{ id:"D5-087", domain:5, obj:"5.4", diff:"medium", q:"A nightly job that previously produced 1.2 million rows suddenly produces 400,000, but no error is thrown. An automated quality check that compares row counts to historical norms would BEST flag this as a(n):", options:["Successful run requiring no action","Anomaly indicating a possible data quality problem","Encryption failure","Improvement in performance"], answer:1, explain:"<strong>Anomaly indicating a possible data quality problem</strong> is correct: a sharp, unexplained drop in row count against historical norms signals a likely upstream issue that monitoring should flag.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Successful run requiring no action</b>: the large unexplained drop is suspicious and warrants investigation.</span><span class='qd'><b>Encryption failure</b>: row counts have nothing to do with encryption.</span><span class='qd'><b>Improvement in performance</b>: fewer rows is not inherently a performance gain and ignores the data loss.</span>" },
{ id:"D5-088", domain:5, obj:"5.4", diff:"hard", q:"A team's reports are occasionally wrong because someone edits the production SQL directly without review. The MOST effective governance fix is to:", options:["Make the reports a brighter color","Require all changes through source control with peer review","Increase the data retention window","Add more rows to the source table"], answer:1, explain:"<strong>Require all changes through source control with peer review</strong> prevents unreviewed edits, providing history, accountability, and a quality gate that catches errors before they reach production.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Make the reports a brighter color</b>: styling does not prevent faulty SQL edits.</span><span class='qd'><b>Increase the data retention window</b>: retention does not control who edits production code.</span><span class='qd'><b>Add more rows to the source table</b>: adding rows does not address uncontrolled changes.</span>" },
{ id:"D5-089", domain:5, obj:"5.1", diff:"easy", q:"Which of the following BEST defines a 'golden record' in master data management?", options:["A backup copy stored offsite","The most recently deleted record","The single, authoritative, deduplicated version of an entity","A randomly sampled row"], answer:2, explain:"<strong>The single, authoritative, deduplicated version of an entity</strong> defines a golden record, the trusted master version that MDM produces by reconciling duplicates.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A backup copy stored offsite</b>: a backup is for recovery, not the authoritative master version.</span><span class='qd'><b>The most recently deleted record</b>: a deleted record is not authoritative or current.</span><span class='qd'><b>A randomly sampled row</b>: a random sample is not a curated authoritative entity.</span>" },
{ id:"D5-090", domain:5, obj:"5.2", diff:"medium", q:"An organization must prove to an external assessor that it consistently applies its retention, access, and breach policies. The mechanism that produces this evidence over time is the:", options:["Color palette","Confusion matrix","Audit trail / logging","Histogram"], answer:2, explain:"<strong>Audit trail / logging</strong> records actions and policy enforcement over time, providing the evidence an external assessor needs to verify consistent compliance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Color palette</b>: a color palette governs visualization styling, not compliance evidence.</span><span class='qd'><b>Confusion matrix</b>: a confusion matrix evaluates models, not policy adherence.</span><span class='qd'><b>Histogram</b>: a histogram shows distributions, not an evidentiary record.</span>" },
{ id:"D5-091", domain:5, obj:"5.3", diff:"medium", q:"Which statement BEST distinguishes anonymization from pseudonymization?", options:["Anonymization always uses encryption; pseudonymization never does","Pseudonymization deletes the data; anonymization copies it","They are identical terms with no difference","Anonymization is irreversible; pseudonymization can be reversed with a key"], answer:3, explain:"<strong>Anonymization is irreversible; pseudonymization can be reversed with a key</strong> is the key distinction: anonymized data cannot be re-linked, while pseudonymized data retains a protected key for re-identification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Anonymization always uses encryption; pseudonymization never does</b>: neither claim is accurate; encryption is a separate technique.</span><span class='qd'><b>Pseudonymization deletes the data; anonymization copies it</b>: pseudonymization replaces identifiers rather than deleting data.</span><span class='qd'><b>They are identical terms with no difference</b>: they differ specifically on reversibility.</span>" },
{ id:"D5-092", domain:5, obj:"5.4", diff:"medium", q:"An analyst profiles a new feed and finds a numeric 'age' column with values like 250 and -5. This profiling result reveals a problem with which quality dimension?", options:["Replication count","Encryption strength","Retention length","Validity (values outside an acceptable range)"], answer:3, explain:"<strong>Validity (values outside an acceptable range)</strong> is the dimension violated when age contains impossible values like 250 or -5, which fall outside the legitimate range.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Replication count</b>: replication concerns the number of copies, not value plausibility.</span><span class='qd'><b>Encryption strength</b>: encryption is a security measure, not value validity.</span><span class='qd'><b>Retention length</b>: retention is about storage duration, not whether values are plausible.</span>" },
{ id:"D5-093", domain:5, obj:"5.1", diff:"medium", q:"A team sets a rule that the warehouse refreshes from source systems every 15 minutes, while a separate executive snapshot is frozen daily. Defining these refresh intervals is part of governing:", options:["Encryption keys","Chart color schemes","Data versioning and refresh cadence","Penetration testing scope"], answer:2, explain:"<strong>Data versioning and refresh cadence</strong> governs how often data is refreshed and how point-in-time versions are captured, matching the 15-minute refresh and daily snapshot rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption keys</b>: key management is a security task, not refresh scheduling.</span><span class='qd'><b>Chart color schemes</b>: color schemes are visualization styling, unrelated to refresh cadence.</span><span class='qd'><b>Penetration testing scope</b>: pen test scope concerns security testing, not data refresh.</span>" },
{ id:"D5-094", domain:5, obj:"5.2", diff:"hard", q:"A company wants to reduce breach impact and regulatory exposure for personal data it rarely uses but must retain for legal reasons. The MOST appropriate control is to:", options:["Encrypt and tightly restrict access to the archived personal data","Publish the data openly to save storage","Disable all logging on the archive","Replicate it to as many regions as possible"], answer:0, explain:"<strong>Encrypt and tightly restrict access to the archived personal data</strong> minimizes breach impact and regulatory exposure while honoring the legal requirement to retain the data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish the data openly to save storage</b>: publishing personal data is a severe privacy violation.</span><span class='qd'><b>Disable all logging on the archive</b>: removing logs weakens oversight and incident detection.</span><span class='qd'><b>Replicate it to as many regions as possible</b>: spreading personal data widely increases exposure and jurisdictional risk.</span>" },
{ id:"D5-095", domain:5, obj:"5.3", diff:"medium", q:"A SaaS analytics tool processes employee data on behalf of a client company. Under GDPR terminology, the SaaS tool acts as the:", options:["Data controller","Data subject","Supervisory authority","Data processor"], answer:3, explain:"<strong>Data processor</strong> processes personal data on behalf of and under the instructions of the controller, which is the role of the SaaS tool serving the client.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data controller</b>: the controller (the client company) determines the purposes and means of processing.</span><span class='qd'><b>Data subject</b>: the data subject is the individual whose data is processed, here the employees.</span><span class='qd'><b>Supervisory authority</b>: a supervisory authority is the regulator that enforces GDPR, not a processor.</span>" },
{ id:"D5-096", domain:5, obj:"5.4", diff:"hard", q:"A model retrained monthly shows stable accuracy in tests but rising real-world errors. Monitoring reveals incoming categories the model never saw in training. This is BEST characterized as:", options:["A successful deployment needing no change","An encryption misconfiguration","A retention policy violation","Concept/data drift requiring retraining on representative data"], answer:3, explain:"<strong>Concept/data drift requiring retraining on representative data</strong> fits: new unseen categories indicate the live data has drifted from training, so retraining on current, representative data is needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A successful deployment needing no change</b>: rising real-world errors contradict a no-change conclusion.</span><span class='qd'><b>An encryption misconfiguration</b>: encryption settings do not cause unseen input categories.</span><span class='qd'><b>A retention policy violation</b>: retention governs storage duration, not model input distribution.</span>" },
{ id:"D5-097", domain:5, obj:"5.1", diff:"hard", q:"After a merger, two CRMs each claim to be authoritative for customer data, causing conflicting updates. The BEST long-term governance solution is to:", options:["Establish a single source of truth via an MDM program","Let each system keep its own version indefinitely","Delete one CRM's data without analysis","Encrypt both systems and stop reconciling"], answer:0, explain:"<strong>Establish a single source of truth via an MDM program</strong> resolves dual-authority conflicts by reconciling entities into governed golden records that all systems consume.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Let each system keep its own version indefinitely</b>: this perpetuates the conflicting-update problem rather than solving it.</span><span class='qd'><b>Delete one CRM's data without analysis</b>: deleting without reconciliation risks losing valid, unique records.</span><span class='qd'><b>Encrypt both systems and stop reconciling</b>: encryption does not address which source is authoritative.</span>" },
{ id:"D5-098", domain:5, obj:"5.2", diff:"medium", q:"A data ethics committee rejects a project that would secretly track app users' location to sell to advertisers, even though buried consent language technically permits it. Their rejection reflects which idea?", options:["Legality and ethics are always identical","Ethics can demand higher standards than minimum legal compliance","Ethics only matters if a breach occurs","Ethics applies only to encrypted data"], answer:1, explain:"<strong>Ethics can demand higher standards than minimum legal compliance</strong> captures the committee's reasoning: just because something is technically permitted does not make it ethically acceptable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Legality and ethics are always identical</b>: the scenario shows them diverging, with legal-but-unethical conduct.</span><span class='qd'><b>Ethics only matters if a breach occurs</b>: ethical review applies proactively, not only after incidents.</span><span class='qd'><b>Ethics applies only to encrypted data</b>: ethics governs all data handling regardless of encryption.</span>" },
{ id:"D5-099", domain:5, obj:"5.3", diff:"hard", q:"A bank must let auditors query transaction patterns without exposing customer identities, while fraud investigators still need full identity access on demand. The BEST design is to:", options:["Give everyone full access for simplicity","Anonymize the data so no one can re-identify it","Apply role-based access with masking for auditors and full access for investigators","Encrypt only the dashboard titles"], answer:2, explain:"<strong>Apply role-based access with masking for auditors and full access for investigators</strong> tailors visibility to each role, hiding identities from auditors while preserving full access where legitimately required.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Give everyone full access for simplicity</b>: blanket full access violates least privilege and exposes identities needlessly.</span><span class='qd'><b>Anonymize the data so no one can re-identify it</b>: irreversible anonymization would block the investigators' legitimate need for identities.</span><span class='qd'><b>Encrypt only the dashboard titles</b>: encrypting titles protects nothing meaningful about customer identities.</span>" },
{ id:"D5-100", domain:5, obj:"5.4", diff:"medium", q:"A team wants a repeatable, documented standard so its data quality and testing processes are consistent and auditable across projects. Adopting an internationally recognized standard such as ISO for these processes PRIMARILY provides:", options:["Faster SQL execution","A consistent, recognized framework that improves trust and auditability","Automatic data anonymization","Reduced storage costs"], answer:1, explain:"<strong>A consistent, recognized framework that improves trust and auditability</strong> is the primary value of adopting an ISO-style standard, standardizing quality and testing processes across projects.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Faster SQL execution</b>: standards do not directly accelerate queries.</span><span class='qd'><b>Automatic data anonymization</b>: a process standard does not itself anonymize data.</span><span class='qd'><b>Reduced storage costs</b>: standardizing quality processes does not inherently lower storage costs.</span>" }
);
